    --grad-donation: linear-gradient(135deg, #0d2a1f 0%, #0d4f3c 50%, #1a7a58 100%);
    --grad-amber:    linear-gradient(135deg, #f59e0b 0%, #fcd34d 100%);

    /* Sizing */
