    inset: 0;
    background-image:
        radial-gradient(circle at 10% 50%, rgba(245,158,11,0.08) 0%, transparent 50%),
        radial-gradient(circle at 90% 50%, rgba(13,148,136,0.12) 0%, transparent 50%);
    pointer-events: none;
}

.objectives-inner { position: relative; z-index: 1; }

.objectives-text {
    font-size: 1.05rem;
    color: rgba(255,255,255,0.8);
    max-width: 640px;
    margin: 0 auto 60px;
    line-height: 1.8;
}

.obj-list {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 24px;
    max-width: 1000px;
    margin: 0 auto;
}

.obj-item {
    background: rgba(255,255,255,0.08);
    backdrop-filter: blur(10px);
    border: 1px solid rgba(255,255,255,0.15);
    border-radius: var(--radius-lg);
    padding: 36px 24px;
    transition: all 0.4s var(--ease);
}
.obj-item:hover {
    background: rgba(255,255,255,0.14);
    transform: translateY(-6px);
    border-color: rgba(245,158,11,0.4);
    box-shadow: 0 12px 40px rgba(0,0,0,0.15);
}

.obj-num {
    font-family: var(--font-display);
    font-size: 2.8rem;
    font-weight: 900;
    color: rgba(245,158,11,0.3);
    line-height: 1;
    margin-bottom: 16px;
    transition: color 0.3s;
}
.obj-item:hover .obj-num { color: var(--amber); }

.obj-content h4 {
    font-family: var(--font-ui);
    font-size: 1rem;
    font-weight: 700;
    color: white;
    margin-bottom: 10px;
}
.obj-content p {
    font-size: 0.85rem;
    color: rgba(255,255,255,0.65);
    line-height: 1.7;
}

/* ============ IMPACT STORY ============ */
.story-section { background: var(--white); }

.story-card {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 60px;
    align-items: center;
    background: var(--cream);
    border-radius: var(--radius-xl);
    overflow: hidden;
    box-shadow: 0 16px 60px rgba(0,0,0,0.08);
}

.story-img-wrap {
    position: relative;
    height: 100%;
    min-height: 400px;
}
.story-img-wrap img {
    width: 100%; height: 100%;
    object-fit: cover;
    transition: transform 0.5s var(--ease);
}
.story-card:hover .story-img-wrap img { transform: scale(1.04); }

.story-img-badge {
    position: absolute;
    top: 24px; right: 24px;
    width: 48px; height: 48px;
    background: var(--grad-amber);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--text-dark);
    font-size: 1.2rem;
    box-shadow: 0 4px 16px rgba(245,158,11,0.4);
}

.story-body {
    padding: 48px 48px 48px 0;
}

.story-quote-mark {
    font-family: var(--font-display);
    font-size: 5rem;
    color: var(--green-light);
    opacity: 0.3;
    line-height: 0.6;
    margin-bottom: 16px;
}

.story-body h3 {
    font-family: var(--font-display);
    font-size: 1.8rem;
    color: var(--text-dark);
    margin-bottom: 20px;
}

.story-main {
    font-size: 1rem;
    font-weight: 500;
    color: var(--text-mid);
    line-height: 1.75;
    margin-bottom: 14px;
}
.story-body-text {
    font-size: 0.9rem;
    color: var(--text-light);
    line-height: 1.8;
    margin-bottom: 28px;
}

.story-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    margin-bottom: 32px;
}
.story-tag {
    display: flex;
    align-items: center;
    gap: 6px;
    background: var(--grad-soft);
    color: var(--green-deep);
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    padding: 6px 14px;
    border-radius: 100px;
    border: 1px solid rgba(26,122,88,0.2);
}

/* ============ DONATION SECTION ============ */
.donation-section { background: var(--off-white); }

.donation-bg {
    position: absolute;
    inset: 0;
    background: var(--grad-donation);
    pointer-events: none;
}

.donation-inner {
    position: relative;
    z-index: 1;
    display: grid;
    grid-template-columns: 1.1fr 0.9fr;
    gap: 48px;
    align-items: center;
}

.donation-desc {
    font-size: 1rem;
    color: rgba(255,255,255,0.75);
    line-height: 1.75;
    margin-bottom: 36px;
}

.donation-impact {
    display: flex;
    flex-direction: column;
    gap: 16px;
}
.impact-row {
    display: flex;
    align-items: center;
    gap: 20px;
    padding: 16px 20px;
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: var(--radius);
    transition: all 0.3s;
}
.impact-row:hover {
    background: rgba(255,255,255,0.14);
    border-color: rgba(245,158,11,0.35);
    transform: translateX(6px);
}
.impact-amt {
    font-family: var(--font-display);
    font-size: 1.2rem;
    font-weight: 700;
    color: var(--amber);
    min-width: 64px;
    flex-shrink: 0;
}
.impact-desc {
    font-size: 0.88rem;
    color: rgba(255,255,255,0.75);
    line-height: 1.5;
}

/* Donation card */
.donation-card {
    padding: 36px;
    background: rgba(255,255,255,0.1) !important;
    border-color: rgba(255,255,255,0.18) !important;
    min-width: 0;
}

.donation-card-header {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 28px;
    padding-bottom: 20px;
    border-bottom: 1px solid rgba(255,255,255,0.15);
}
.donation-card-header i {
    font-size: 1.5rem;
    color: var(--amber);
    flex-shrink: 0;
}
.donation-card-header h3 {
    font-family: var(--font-display);
    font-size: 1.25rem;
    color: white;
    white-space: nowrap;
}

.bank-details { margin-bottom: 28px; }

/* Each row is now stacked: label on top, value below */
.bank-row {
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding: 12px 0;
    border-bottom: 1px solid rgba(255,255,255,0.08);
}
.bank-label {
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: rgba(255,255,255,0.45);
}
.bank-val {
    font-family: var(--font-ui);
    font-size: 0.95rem;
    font-weight: 600;
    color: rgba(255,255,255,0.95);
    text-align: left;
    word-break: break-word;
}
.copy-able {
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    transition: color 0.3s;
}
.copy-able:hover { color: var(--amber); }
.copy-icon { font-size: 0.82rem; opacity: 0.55; }

.donation-note {
    text-align: center;
    margin-top: 16px;
    font-size: 0.8rem;
    color: rgba(255,255,255,0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
}

/* ============ CONTACT SECTION ============ */
.contact-section { background: var(--cream); }

.contact-grid {
    display: grid;
    grid-template-columns: 1fr 1.5fr;
    gap: 48px;
    align-items: start;
}

.contact-card {
    padding: 40px;
    background: var(--white) !important;
    border-color: rgba(26,122,88,0.1) !important;
    backdrop-filter: none !important;
    box-shadow: 0 4px 24px rgba(0,0,0,0.06) !important;
}

.contact-item {
    display: flex;
    gap: 20px;
    align-items: flex-start;
    padding: 20px 0;
    border-bottom: 1px solid rgba(0,0,0,0.06);
}
.contact-item:last-child { border-bottom: none; }

.contact-icon {
    width: 44px; height: 44px;
    background: var(--grad-soft);
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--green-mid);
    font-size: 1rem;
    flex-shrink: 0;
}

.contact-detail h4 {
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--text-light);
    margin-bottom: 6px;
}
.contact-detail a,
.contact-detail span {
    display: block;
    font-size: 0.9rem;
    color: var(--text-mid);
    line-height: 1.7;
    transition: color 0.3s;
}
.contact-detail a:hover { color: var(--green-mid); }

/* Contact Form */
.contact-form {
    padding: 40px;
    background: var(--white) !important;
    border-color: rgba(26,122,88,0.12) !important;
    backdrop-filter: none !important;
    box-shadow: 0 4px 24px rgba(0,0,0,0.06) !important;
}

.form-group {
    position: relative;
    margin-bottom: 24px;
}
.form-group label {
    display: block;
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text-mid);
    margin-bottom: 8px;
    letter-spacing: 0.04em;
}
.form-group input,
.form-group textarea {
    width: 100%;
    padding: 14px 18px;
    background: var(--cream);
    border: 2px solid transparent;
    border-radius: var(--radius);
    font-family: var(--font-body);
    font-size: 0.95rem;
    color: var(--text-dark);
    outline: none;
    transition: all 0.3s var(--ease);
    resize: vertical;
}
.form-group input::placeholder,
.form-group textarea::placeholder { color: var(--text-light); }
.form-group input:focus,
.form-group textarea:focus {
    border-color: var(--green-mid);
    background: var(--white);
    box-shadow: 0 0 0 4px rgba(26,122,88,0.1);
}

.form-success {
    text-align: center;
    padding: 32px;
    background: linear-gradient(135deg, rgba(26,122,88,0.08), rgba(13,148,136,0.05));
    border: 1px solid rgba(26,122,88,0.2);
    border-radius: var(--radius-lg);
    margin-bottom: 24px;
    color: var(--green-deep);
}
.form-success i { font-size: 2.5rem; color: var(--green-mid); margin-bottom: 12px; }
.form-success h3 { font-family: var(--font-display); margin-bottom: 8px; }
.form-error-msg {
    background: rgba(239,68,68,0.08);
    border: 1px solid rgba(239,68,68,0.3);
    color: #dc2626;
    padding: 12px 18px;
    border-radius: var(--radius);
    font-size: 0.88rem;
    margin-bottom: 20px;
}

/* ============ FOOTER ============ */
.footer {
    background: var(--footer-bg);
    position: relative;
    padding-top: 0;
}

.footer-wave {
    height: 60px;
    overflow: hidden;
    margin-bottom: -2px;
}
.footer-wave svg { width: 100%; height: 100%; display: block; }

.footer-content {
    max-width: 1200px;
    margin: 0 auto;
    padding: 60px 24px 40px;
    display: grid;
    grid-template-columns: 2fr 1fr 1fr;
    gap: 48px;
}

.footer-logo {
    font-family: var(--font-display);
    font-size: 1.8rem;
    font-weight: 900;
    color: white;
    margin-bottom: 12px;
}
.footer-brand p {
    font-size: 0.9rem;
    color: rgba(255,255,255,0.5);
    margin-bottom: 24px;
    line-height: 1.7;
}
.footer-social {
    display: flex;
    gap: 12px;
}
.footer-social a {
    width: 38px; height: 38px;
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.12);
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    color: rgba(255,255,255,0.6);
    font-size: 0.9rem;
    transition: all 0.3s;
}
.footer-social a:hover {
    background: var(--green-mid);
    border-color: var(--green-mid);
    color: white;
    transform: translateY(-3px);
}

.footer-links h4,
.footer-contact h4 {
    font-family: var(--font-ui);
    font-size: 0.85rem;
    font-weight: 700;
    color: rgba(255,255,255,0.9);
    letter-spacing: 0.1em;
    text-transform: uppercase;
    margin-bottom: 20px;
}
.footer-links ul li { margin-bottom: 10px; }
.footer-links ul li a {
    font-size: 0.88rem;
    color: rgba(255,255,255,0.5);
    transition: all 0.3s;
    display: inline-flex;
    align-items: center;
    gap: 6px;
}
.footer-links ul li a:hover { color: var(--amber); padding-left: 4px; }

.footer-contact p {
    display: flex;
    align-items: center;
    gap: 10px;
    font-size: 0.88rem;
    color: rgba(255,255,255,0.5);
    margin-bottom: 12px;
}
.footer-contact i { color: var(--green-light); width: 16px; }

.footer-bottom {
    border-top: 1px solid rgba(255,255,255,0.06);
    padding: 24px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    max-width: 1200px;
    margin: 0 auto;
    font-size: 0.82rem;
    color: rgba(255,255,255,0.35);
}

/* ============ SCROLL TO TOP ============ */
.scroll-top {
    position: fixed;
    bottom: 32px; right: 32px;
    width: 48px; height: 48px;
    background: var(--grad-main);
    color: white;
    border: none;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1rem;
    cursor: pointer;
    box-shadow: 0 4px 20px rgba(13,79,60,0.35);
    transform: translateY(80px);
    opacity: 0;
    transition: all 0.4s var(--ease);
    z-index: 999;
}
.scroll-top.visible {
    transform: translateY(0);
    opacity: 1;
}
.scroll-top:hover { transform: translateY(-4px); }

/* ============ SCROLL REVEAL ANIMATIONS ============ */
.reveal-up,
.reveal-left,
.reveal-right {
    opacity: 0;
    transition: opacity 0.7s var(--ease), transform 0.7s var(--ease);
    transition-delay: var(--delay, 0s);
}
.reveal-up    { transform: translateY(50px); }
.reveal-left  { transform: translateX(-60px); }
.reveal-right { transform: translateX(60px); }

.revealed.reveal-up    { opacity: 1; transform: translateY(0); }
.revealed.reveal-left  { opacity: 1; transform: translateX(0); }
.revealed.reveal-right { opacity: 1; transform: translateX(0); }

/* ============ RESPONSIVE ============ */
@media (max-width: 1024px) {
    .facilities-grid { grid-template-columns: repeat(2, 1fr); }
    .obj-list { grid-template-columns: repeat(2, 1fr); }
    .footer-content { grid-template-columns: 1fr 1fr; }
    .footer-brand { grid-column: 1 / -1; }
}

@media (max-width: 900px) {
    .about-grid,
    .vm-grid,
    .story-card,
    .donation-inner,
    .contact-grid { grid-template-columns: 1fr; }

    .about-grid { gap: 48px; }
    .story-body { padding: 32px; }
    .story-img-wrap { min-height: 280px; }

    .hero-stats { padding: 16px 24px; }
    .stat-item { padding: 0 16px; }
    .stat-num { font-size: 1.6rem; }
}

@media (max-width: 768px) {
    :root { --nav-h: 68px; }

    .section { padding: 72px 0; }

    /* Mobile nav */
    .nav-menu {
        position: fixed;
        top: var(--nav-h);
        left: 0; right: 0;
        background: rgba(13,79,60,0.98);
        backdrop-filter: blur(20px);
        padding: 24px;
        transform: translateY(-110%);
        opacity: 0;
        transition: all 0.4s var(--ease);
        border-bottom: 1px solid rgba(255,255,255,0.1);
    }
    .nav-menu.open { transform: translateY(0); opacity: 1; }
    .nav-list { flex-direction: column; gap: 4px; }
    .nav-link { display: block; padding: 12px 16px; font-size: 1rem; }
    .nav-cta { display: none; }
    .hamburger { display: flex; }

    .title-main { font-size: clamp(4rem, 18vw, 6rem); }

    .facilities-grid { grid-template-columns: 1fr 1fr; }

    .donation-card { padding: 28px; }
    .contact-form { padding: 28px; }
    .contact-card { padding: 28px; }

    .footer-content { grid-template-columns: 1fr; gap: 32px; }
    .footer-bottom { flex-direction: column; gap: 8px; text-align: center; }
}

@media (max-width: 520px) {
    .facilities-grid { grid-template-columns: 1fr; }
    .obj-list { grid-template-columns: 1fr; }
    .hero-stats {
        flex-direction: column;
        gap: 12px;
        padding: 20px;
    }
    .stat-divider { width: 60%; height: 1px; }
    .hero-actions { flex-direction: column; align-items: center; }
}

/* ============ BOSS CHANGES ============ */

/* 1. HERO — 600px height, logo image */
.hero { height: 600px; min-height: 600px; }
.nav-logo-img { height: 52px; width: auto; object-fit: contain; }
.logo-icon, .logo-text { display: none; }

/* Remove hero stats (hidden via JS removal, also hide via CSS safety) */
.hero-stats { display: none !important; }

/* 2. ABOUT — title single line, remove pillars */
.section-heading { white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
@media (max-width: 900px) { .section-heading { white-space: normal; font-size: clamp(1.5rem, 4vw, 2.2rem); } }
.about-pillars { display: none !important; }

/* 3. VISION & MISSION — proper bg colors, contrast, left-align */
.vision-section { background: #f5f5f5 !important; }
.vision-bg-shape { display: none; }
.vm-grid { gap: 40px; }

.vm-card:first-child {
    background: #1a7a58 !important;
    border: none !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    padding: 48px 44px;
}
.vm-card:last-child {
    background: #f97316 !important;
    border: none !important;
    backdrop-filter: none !important;
    -webkit-backdrop-filter: none !important;
    padding: 48px 44px;
}
.vm-card h3 { color: #ffffff !important; font-size: 1.6rem; margin-bottom: 12px; }
.vm-card p  { color: #ffffff !important; text-align: left !important; line-height: 1.75; font-size: 1rem; }
.vm-card .vm-icon { margin-bottom: 20px; }

/* section-header on light bg needs dark text */
.vision-section .section-heading.light { color: #1a1a2e !important; }
.vision-section .section-sub.light     { color: #3d4451 !important; }
.vision-section .section-tag.tag-light {
    background: rgba(26,122,88,0.1) !important;
    color: #0d4f3c !important;
    border-color: rgba(26,122,88,0.3) !important;
}

/* 4. FACILITIES — remove icons (CSS safety), bigger heading, equal height cards */
.facility-icon { display: none !important; }
.facility-body h3 { font-size: 1.25rem !important; color: #0d4f3c !important; margin-top: 4px; }
.facilities-grid { align-items: stretch; }
.facility-card { display: flex; flex-direction: column; height: 100%; }
.facility-body { flex: 1; }

/* 5. OBJECTIVES — better contrast, bold numbers */
.obj-num { color: #fcd34d !important; font-weight: 900 !important; opacity: 1 !important; }
.obj-item:hover .obj-num { color: #f59e0b !important; }
.obj-content h4 { color: #ffffff !important; font-size: 1.05rem; }
.obj-content p  { color: rgba(255,255,255,0.85) !important; }

/* 6. STORY — better paragraph spacing */
.story-main, .story-body-text { text-align: justify; }
.story-main { margin-bottom: 18px; }
.story-body-text { margin-bottom: 32px; }

/* 7. CONTACT — remove info, centre form */
.contact-grid { grid-template-columns: 1fr !important; }
.contact-form-wrap {
    max-width: 560px;
    margin: 0 auto;
    width: 100%;
}
.contact-info { display: none !important; }

/* 8. GLOBAL — section padding 60-80px, justify paragraphs */
.section { padding: 70px 0; }
p, .about-intro, .about-body, .section-sub, .objectives-text, .donation-desc { text-align: justify; }
.hero-text, .hero-tagline { text-align: center !important; }

/* 9. UI POLISH — consistent radius, button shadows, hover */
.btn { border-radius: 14px !important; }
.facility-card, .vm-card, .obj-item, .story-card, .donation-card, .contact-form, .contact-card {
    border-radius: 14px !important;
}
.facility-card:hover {
    transform: translateY(-8px);
    box-shadow: 0 16px 40px rgba(13,79,60,0.18);
}
.obj-item:hover { transform: translateY(-5px); }

</style>
</head>
<body>

<header id="navbar" class="navbar">
  <div class="nav-container">
    <a href="#home" class="nav-logo"><span class="logo-icon">🌿</span><span class="logo-text">IRCDS</span></a>
    <nav class="nav-menu" id="navMenu">
      <ul class="nav-list">
        <li><a href="#home"       class="nav-link">Home</a></li>
        <li><a href="#about"      class="nav-link">About</a></li>
        <li><a href="#vision"     class="nav-link">Vision</a></li>
        <li><a href="#facilities" class="nav-link">Facilities</a></li>
        <li><a href="#objectives" class="nav-link">Objectives</a></li>
        <li><a href="#story"      class="nav-link">Story</a></li>
        <li><a href="#donation"   class="nav-link">Donation</a></li>
        <li><a href="#contact"    class="nav-link">Contact</a></li>
      </ul>
    </nav>
    <a href="https://www.kokanngo.org/donation" target="_blank" rel="noopener noreferrer" class="nav-cta">Donate Now</a>
    <button class="hamburger" id="hamburger" aria-label="Toggle menu"><span></span><span></span><span></span></button>
  </div>
</header>

<!-- HERO -->
<section id="home" class="hero">
  <div class="hero-bg" id="heroBg" style="background-image:url('data:image/jpeg;base64,');"></div>
  <div class="hero-overlay"></div>
  <div class="orb orb-1"></div><div class="orb orb-2"></div><div class="orb orb-3"></div>
  <div class="hero-content">
    <div class="hero-badge reveal-up" style="--delay:0.1s">Since 1986</div>
    <h1 class="hero-title reveal-up" style="--delay:0.2s">
