<button class="scroll-top" id="scrollTop" aria-label="Scroll to top"><i class="fas fa-arrow-up"></i></button>

<script>
/* =============================================
   IRCDS — script.js
   Handles: navbar, parallax, scroll reveal,
   counter animations, mobile menu, copy, scroll-top
   ============================================= */

document.addEventListener('DOMContentLoaded', () => {

    /* ==========================================
       1. NAVBAR — transparent → solid on scroll
       ========================================== */
    const navbar   = document.getElementById('navbar');
    const hamburger = document.getElementById('hamburger');
    const navMenu  = document.getElementById('navMenu');
    const navLinks = document.querySelectorAll('.nav-link');

    function updateNavbar() {
        if (window.scrollY > 60) {
            navbar.classList.add('scrolled');
        } else {
            navbar.classList.remove('scrolled');
        }
    }
    updateNavbar();
    window.addEventListener('scroll', updateNavbar, { passive: true });

    // Hamburger toggle
    hamburger.addEventListener('click', () => {
        hamburger.classList.toggle('open');
        navMenu.classList.toggle('open');
    });

    // Close nav on link click (mobile)
    navLinks.forEach(link => {
        link.addEventListener('click', () => {
            hamburger.classList.remove('open');
            navMenu.classList.remove('open');
        });
    });

    /* ==========================================
       2. ACTIVE NAV LINK — highlight on scroll
       ========================================== */
    const sections = document.querySelectorAll('section[id]');

    function highlightNav() {
        const scrollPos = window.scrollY + 120;
        sections.forEach(section => {
            const top    = section.offsetTop;
            const bottom = top + section.offsetHeight;
            const id     = section.getAttribute('id');
            const link   = document.querySelector(`.nav-link[href="#${id}"]`);
            if (link) {
                if (scrollPos >= top && scrollPos < bottom) {
                    navLinks.forEach(l => l.classList.remove('active'));
                    link.classList.add('active');
                }
            }
        });
    }
    window.addEventListener('scroll', highlightNav, { passive: true });

    /* ==========================================
       3. PARALLAX HERO BACKGROUND
       ========================================== */
    const heroBg = document.getElementById('heroBg');

    function parallaxHero() {
        if (!heroBg) return;
        const scrolled = window.scrollY;
        heroBg.style.transform = `translateY(${scrolled * 0.4}px)`;
    }
    window.addEventListener('scroll', parallaxHero, { passive: true });

    /* ==========================================
       4. SCROLL REVEAL ANIMATIONS
       ========================================== */
    const revealEls = document.querySelectorAll('.reveal-up, .reveal-left, .reveal-right');

    const revealObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.classList.add('revealed');
                // Unobserve after reveal to save resources
                revealObserver.unobserve(entry.target);
            }
        });
    }, {
        threshold: 0.12,
        rootMargin: '0px 0px -60px 0px'
    });

    revealEls.forEach(el => revealObserver.observe(el));

    /* ==========================================
       5. ANIMATED COUNTER — hero stats
       ========================================== */
    const counters = document.querySelectorAll('.stat-num[data-count]');
    let countersTriggered = false;

    function animateCounter(el) {
        const target  = parseInt(el.getAttribute('data-count'), 10);
        const duration = 2000;
        const step     = target / (duration / 16);
        let current    = 0;

        const timer = setInterval(() => {
            current += step;
            if (current >= target) {
                el.textContent = target;
                clearInterval(timer);
            } else {
                el.textContent = Math.floor(current);
            }
        }, 16);
    }

    // Trigger counters when hero stats come into view
    const heroStats = document.querySelector('.hero-stats');
    if (heroStats) {
        const statsObserver = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting && !countersTriggered) {
                    countersTriggered = true;
                    counters.forEach(counter => animateCounter(counter));
                    statsObserver.disconnect();
                }
            });
        }, { threshold: 0.5 });
        statsObserver.observe(heroStats);
    }

    /* ==========================================
       6. SCROLL TO TOP BUTTON
       ========================================== */
    const scrollTopBtn = document.getElementById('scrollTop');

    window.addEventListener('scroll', () => {
        if (window.scrollY > 400) {
            scrollTopBtn.classList.add('visible');
        } else {
            scrollTopBtn.classList.remove('visible');
        }
    }, { passive: true });

    scrollTopBtn.addEventListener('click', () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    });

    /* ==========================================
       7. COPY TO CLIPBOARD — bank details
       ========================================== */
    const copyEls = document.querySelectorAll('.copy-able');

    copyEls.forEach(el => {
        el.addEventListener('click', () => {
            const text = el.getAttribute('data-copy');
            if (!text) return;

            navigator.clipboard.writeText(text).then(() => {
                const icon = el.querySelector('.copy-icon');
                const origClass = 'fas fa-copy copy-icon';
                if (icon) {
                    icon.className = 'fas fa-check copy-icon';
                    el.style.color = 'var(--amber)';
                    setTimeout(() => {
                        icon.className = origClass;
                        el.style.color = '';
                    }, 2000);
                }
            }).catch(() => {
                // Fallback for older browsers
                const area = document.createElement('textarea');
                area.value = text;
                document.body.appendChild(area);
                area.select();
                document.execCommand('copy');
                document.body.removeChild(area);
            });
        });
    });

    /* ==========================================
       8. SMOOTH SCROLL — anchor links
       ========================================== */
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', (e) => {
            const target = document.querySelector(anchor.getAttribute('href'));
            if (target) {
                e.preventDefault();
                const offset = parseInt(getComputedStyle(document.documentElement)
                    .getPropertyValue('--nav-h')) || 80;
                const top = target.getBoundingClientRect().top + window.scrollY - offset;
                window.scrollTo({ top, behavior: 'smooth' });
            }
        });
    });

    /* ==========================================
       9. FACILITY CARD — stagger reveal enhancement
       ========================================== */
    const facilityCards = document.querySelectorAll('.facility-card');
    facilityCards.forEach((card, i) => {
        card.style.setProperty('--delay', `${i * 0.1}s`);
    });

    /* ==========================================
       10. ORBS — subtle mouse parallax
       ========================================== */
    const orbs = document.querySelectorAll('.orb');
    if (orbs.length) {
        document.addEventListener('mousemove', (e) => {
            const cx = window.innerWidth  / 2;
            const cy = window.innerHeight / 2;
            const dx = (e.clientX - cx) / cx;
            const dy = (e.clientY - cy) / cy;

            orbs.forEach((orb, i) => {
                const factor = (i + 1) * 8;
                orb.style.transform = `translate(${dx * factor}px, ${dy * factor}px)`;
            });
        });
    }

    /* ==========================================
       11. HERO — auto-type tagline effect
       ========================================== */
    const taglineEl = document.querySelector('.hero-tagline');
    if (taglineEl) {
        const text = taglineEl.textContent;
        taglineEl.textContent = '';
        taglineEl.style.opacity = '1';
        let i = 0;
        const typeTimer = setInterval(() => {
            taglineEl.textContent += text[i];
            i++;
            if (i >= text.length) clearInterval(typeTimer);
        }, 60);
    }

    /* ==========================================
       12. IMPACT ROW — scroll-triggered highlight
       ========================================== */
    const impactRows = document.querySelectorAll('.impact-row');
    const rowObserver = new IntersectionObserver((entries) => {
        entries.forEach((entry, i) => {
            if (entry.isIntersecting) {
                setTimeout(() => {
                    entry.target.style.opacity = '1';
                    entry.target.style.transform = 'translateX(0)';
                }, i * 150);
                rowObserver.unobserve(entry.target);
            }
        });
    }, { threshold: 0.4 });

    impactRows.forEach(row => {
        row.style.opacity = '0';
        row.style.transform = 'translateX(-20px)';
        row.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
        rowObserver.observe(row);
    });

    /* ==========================================
       13. FORM — real-time validation feedback
       ========================================== */
    const formInputs = document.querySelectorAll('.contact-form input, .contact-form textarea');
    formInputs.forEach(input => {
        input.addEventListener('blur', () => {
            if (input.value.trim() && input.validity.valid) {
                input.style.borderColor = 'var(--green-mid)';
            } else if (input.value.trim() && !input.validity.valid) {
                input.style.borderColor = '#ef4444';
            }
        });
        input.addEventListener('focus', () => {
            input.style.borderColor = '';
        });
    });

});
</script>
</body>
</html>
